// Parsear datos del request
const raw = $input.first().json ?? {};
const body = raw.body ?? raw;
const normalize = (v) => String(v ?? '').trim();

const accessToken = normalize(body.access_token);
const pageId = normalize(body.page_id);
const videoUrl = normalize(body.video_url);
const videoBase64 = normalize(body.videoBase64);
const title = normalize(body.title || 'Reel publicitario');
const description = normalize(body.description || body.post_text || body.caption || '');
const generatedAt = new Date().toISOString();

if (!accessToken) {
  return [{ json: { status: 'error', message: 'Se requiere access_token', generated_at: generatedAt } }];
}
if (!pageId) {
  return [{ json: { status: 'error', message: 'Se requiere page_id', generated_at: generatedAt } }];
}
if (!videoUrl && !videoBase64) {
  return [{ json: { status: 'error', message: 'Se requiere video_url o videoBase64', generated_at: generatedAt } }];
}

return [{
  json: {
    accessToken,
    pageId,
    videoUrl,
    videoBase64,
    title,
    description,
    generatedAt,
    hasVideoUrl: !!videoUrl,
    hasVideoBase64: !!videoBase64,
  }
}];

// Extraer video_id y upload_url de la fase 1
const response = $input.first().json;
const parsedData = $('Parsear Request').first().json;

const videoId = String(response.video_id || '').trim();
const uploadUrl = String(response.upload_url || '').trim();

if (!videoId || !uploadUrl) {
  throw new Error('Facebook no devolvio video_id o upload_url. Response: ' + JSON.stringify(response));
}

return [{
  json: {
    videoId,
    uploadUrl,
    accessToken: parsedData.accessToken,
    pageId: parsedData.pageId,
    videoUrl: parsedData.videoUrl,
    videoBase64: parsedData.videoBase64,
    title: parsedData.title,
    description: parsedData.description,
    generatedAt: parsedData.generatedAt,
    hasVideoUrl: parsedData.hasVideoUrl,
    hasVideoBase64: parsedData.hasVideoBase64,
  }
}];

// Fase 2: Subir el video al upload_url
const data = $input.first().json;
const request = this.helpers.request;

let videoBuffer;
let fileSize;

if (data.hasVideoUrl && data.videoUrl) {
  // Descargar video desde URL
  const downloadResponse = await request({
    method: 'GET',
    uri: data.videoUrl,
    encoding: null,
    resolveWithFullResponse: true,
  });
  videoBuffer = downloadResponse.body;
  fileSize = videoBuffer.length;
} else if (data.hasVideoBase64 && data.videoBase64) {
  // Decodificar base64
  const cleanBase64 = data.videoBase64.replace(/^data:video\/\w+;base64,/, '');
  videoBuffer = Buffer.from(cleanBase64, 'base64');
  fileSize = videoBuffer.length;
} else {
  throw new Error('No hay video para subir (ni URL ni base64)');
}

// Subir al upload_url de Facebook
const uploadResponse = await request({
  method: 'POST',
  uri: data.uploadUrl,
  headers: {
    'Authorization': `OAuth ${data.accessToken}`,
    'offset': '0',
    'file_size': String(fileSize),
    'Content-Type': 'application/octet-stream',
  },
  body: videoBuffer,
  json: true,
  simple: false,
  resolveWithFullResponse: true,
});

const uploadBody = uploadResponse?.body ?? {};
if (Number(uploadResponse?.statusCode || 500) >= 400) {
  throw new Error('Error subiendo video a Facebook: ' + JSON.stringify(uploadBody));
}

return [{
  json: {
    uploadSuccess: uploadBody.success || true,
    videoId: data.videoId,
    accessToken: data.accessToken,
    pageId: data.pageId,
    title: data.title,
    description: data.description,
    generatedAt: data.generatedAt,
    fileSize,
  }
}];

// Resultado final
const response = $input.first().json;
const uploadData = $('Fase 2 - Subir Video').first().json;

return [{
  json: {
    status: response.success ? 'success' : 'error',
    post_id: response.post_id || null,
    video_id: uploadData.videoId,
    page_id: uploadData.pageId,
    title: uploadData.title,
    description: uploadData.description,
    file_size_bytes: uploadData.fileSize,
    generated_at: uploadData.generatedAt,
    published_at: new Date().toISOString(),
    facebook_response: response,
  }
}];
